arguments.file_text:
using System.ComponentModel.DataAnnotations;

namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    [Required]
    public string Category { get; set; } = string.Empty;

    public string Description { get; set; } = string.Empty;

    [Required, MinLength(1)]
    public List<string> Ingredients { get; set; } = [];

    [Required, MinLength(1)]
    public List<string> Steps { get; set; } = [];

    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings == 0 ? 0 : (double)RatingSum / TotalRatings;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes = GetSeedRecipes();
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    private static List<Recipe> GetSeedRecipes() =>
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple, traditional Neapolitan pizza with fresh ingredients.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = [
                "Preheat oven to 475°F (245°C) with a pizza stone inside.",
                "Stretch dough into a 12-inch round on a floured surface.",
                "Spread crushed tomatoes evenly over the dough.",
                "Tear mozzarella into pieces and distribute over the sauce.",
                "Bake for 10–12 minutes until crust is golden and cheese is bubbly.",
                "Top with fresh basil leaves and a drizzle of olive oil."
            ],
            TotalRatings = 12, RatingSum = 50
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta made with eggs, cheese, and pancetta.",
            Ingredients = ["400g spaghetti", "200g pancetta", "4 egg yolks", "100g Pecorino Romano", "Black pepper"],
            Steps = [
                "Cook spaghetti in salted boiling water until al dente.",
                "Fry pancetta in a large pan until crispy.",
                "Whisk egg yolks with grated Pecorino and plenty of black pepper.",
                "Drain pasta, reserving some cooking water.",
                "Toss hot pasta with pancetta off heat, then stir in the egg mixture quickly.",
                "Add splashes of pasta water to create a creamy sauce. Serve immediately."
            ],
            TotalRatings = 8, RatingSum = 35
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
            Ingredients = ["500g chicken breast", "Yogurt", "Garam masala", "Tomato puree", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = [
                "Marinate chicken in yogurt and spices for at least 1 hour.",
                "Grill or broil chicken until lightly charred.",
                "Sauté onion, garlic, and ginger in a pan until soft.",
                "Add tomato puree and spices, simmer for 15 minutes.",
                "Stir in cream and add the cooked chicken.",
                "Simmer for 10 more minutes. Serve with basmati rice or naan."
            ],
            TotalRatings = 15, RatingSum = 68
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
            Description = "A sweet-savory stir-fried noodle dish with crunchy vegetables.",
            Ingredients = ["200g rice noodles", "2 eggs", "Bean sprouts", "Carrots", "Green onions", "Peanuts", "Pad Thai sauce", "Lime"],
            Steps = [
                "Soak rice noodles in warm water for 30 minutes, then drain.",
                "Scramble eggs in a hot wok, set aside.",
                "Stir-fry julienned carrots and green onions for 2 minutes.",
                "Add noodles and Pad Thai sauce, toss until coated.",
                "Add bean sprouts and scrambled eggs, toss briefly.",
                "Serve topped with crushed peanuts and lime wedges."
            ],
            TotalRatings = 6, RatingSum = 25
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in crispy tortillas with fresh toppings.",
            Ingredients = ["500g ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
            Steps = [
                "Brown ground beef in a skillet, drain excess fat.",
                "Add taco seasoning and water, simmer until thickened.",
                "Warm tortillas in a dry pan or oven.",
                "Fill tortillas with seasoned beef.",
                "Top with shredded lettuce, diced tomato, cheese, sour cream, and salsa."
            ],
            TotalRatings = 10, RatingSum = 42
        },
        new()
        {
            Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Individual cakes with a warm, molten chocolate center.",
            Ingredients = ["200g dark chocolate", "100g butter", "3 eggs", "100g sugar", "50g flour"],
            Steps = [
                "Preheat oven to 425°F (220°C). Grease four ramekins.",
                "Melt chocolate and butter together, let cool slightly.",
                "Whisk eggs and sugar until thick and pale.",
                "Fold chocolate mixture into the eggs, then fold in flour.",
                "Divide batter among ramekins.",
                "Bake for 12–14 minutes until edges are set but center is soft.",
                "Invert onto plates and serve immediately."
            ],
            TotalRatings = 20, RatingSum = 95
        },
        new()
        {
            Id = 7, Title = "Caesar Salad", Category = "Salads",
            Description = "Crisp romaine lettuce with a tangy, anchovy-based dressing.",
            Ingredients = ["Romaine lettuce", "Croutons", "Parmesan cheese", "Anchovy fillets", "Garlic", "Lemon juice", "Olive oil", "Egg yolk", "Dijon mustard"],
            Steps = [
                "Blend anchovy, garlic, egg yolk, lemon juice, and mustard.",
                "Slowly drizzle in olive oil while blending to emulsify.",
                "Tear romaine into bite-sized pieces and place in a large bowl.",
                "Toss with dressing, croutons, and shaved Parmesan."
            ],
            TotalRatings = 5, RatingSum = 21
        }
    ];
}

