arguments.file_text:
@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= DisplayRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              @onmouseover="() => _hover = star"
              @onmouseout="() => _hover = 0"
              role="button"
              title="@star star@(star > 1 ? "s" : "")">
            @(star <= DisplayRating ? "\u2605" : "\u2606")
        </span>
    }
    @if (TotalRatings > 0)
    {
        <span class="rating-info ms-2 text-muted">
            (@AverageRating.ToString("0.0") avg, @TotalRatings ratings)
        </span>
    }
    @if (_submitted)
    {
        <span class="text-success ms-2">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }
    [Parameter] public EventCallback<int> OnRated { get; set; }

    private int _hover;
    private int _userRating;
    private bool _submitted;

    private int DisplayRating => _hover > 0 ? _hover : _userRating > 0 ? _userRating : (int)Math.Round(AverageRating);

    private async Task Rate(int stars)
    {
        _userRating = stars;
        _submitted = true;
        await OnRated.InvokeAsync(stars);
    }
}

.star-rating .star {
    font-size: 1.8rem;
    cursor: pointer;
    transition: color 0.15s;
    color: #ccc;
}

.star-rating .star.filled {
    color: #f5a623;
}

.star-rating .star:hover {
    color: #f5a623;
    transform: scale(1.2);
}

.star-rating .rating-info {
    font-size: 0.9rem;
}

