@page "/"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Recipe Community</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 Recipe Community</h1>
    <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
    @foreach (var category in RecipeService.GetCategories())
    {
        var recipes = RecipeService.GetByCategory(category);
        <div class="col">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <h3 class="card-title">@GetCategoryEmoji(category) @category</h3>
                    <p class="card-text text-muted">@recipes.Count recipe@(recipes.Count != 1 ? "s" : "")</p>
                    <a href="recipes/@category" class="btn btn-outline-primary">Browse Recipes &rarr;</a>
                </div>
            </div>
        </div>
    }
</div>

<div class="text-center mt-5">
    <h4>Have a recipe to share?</h4>
    <a href="submit" class="btn btn-success btn-lg mt-2">Submit a Recipe</a>
</div>

@code {
    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Thai" => "🇹🇭",
        "Mexican" => "🇲🇽",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍽️"
    };
}

arguments.file_text:
@page "/recipes/{Category}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@Category Recipes</PageTitle>

<h1>@Category Recipes</h1>
<p><a href="/">← Back to categories</a></p>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var recipe in recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            @if (recipe.TotalRatings > 0)
                            {
                                <span class="text-warning">
                                    @(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))
                                </span>
                                <small class="text-muted">(@recipe.AverageRating.ToString("0.0"))</small>
                            }
                            else
                            {
                                <small class="text-muted">No ratings yet</small>
                            }
                        </div>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string Category { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
    <a href="/">← Back to Home</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="recipes/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <div class="mb-4">
        <h5>Rate this recipe:</h5>
        <StarRating RecipeId="@recipe.Id"
                    AverageRating="@recipe.AverageRating"
                    TotalRatings="@recipe.TotalRatings"
                    OnRated="HandleRating" />
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h4 class="mb-0">Ingredients</h4></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
